/**
 * Registration tests for the sync Task dispatcher (PreToolUse[Task]).
 *
 * Locks two contracts end-to-end through syncTaskDispatcher rather than
 * the individual hooks, so removing a hook from TASK_HOOKS fails a test:
 *
 *  1. spawn-intent-logger is registered: dispatching a Task input with a
 *     subagent_type writes a source:"pretool" entry to subagent-spawns.jsonl.
 *     (#2374 follow-up — the logger was previously only unit-tested, so it
 *     could be deleted from the dispatcher without any test noticing.)
 *
 *  2. task-agent-advisor is registered: a domain-shaped general-purpose
 *     dispatch surfaces the specialist nudge in the merged additionalContext.
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';

const { mockBufferWrite } = vi.hoisted(() => ({
  mockBufferWrite: vi.fn(),
}));

vi.mock('../../lib/analytics-buffer.js', () => ({
  bufferWrite: mockBufferWrite,
  flush: vi.fn(),
  pendingCount: vi.fn(() => 0),
  _resetForTesting: vi.fn(),
}));

import { syncTaskDispatcher } from '../../pretool/task/sync-task-dispatcher.js';

function makeInput(toolInput: Record<string, unknown>, overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Task',
    session_id: 'session-dispatcher-test',
    tool_input: toolInput,
    ...overrides,
  };
}

function spawnLogEntries(): Array<Record<string, unknown>> {
  return mockBufferWrite.mock.calls
    .filter((c: unknown[]) => typeof c[0] === 'string' && c[0].includes('subagent-spawns.jsonl'))
    .map((c: unknown[]) => JSON.parse((c[1] as string).trim()));
}

beforeEach(() => {
  mockBufferWrite.mockClear();
});

describe('syncTaskDispatcher — spawn-intent-logger registration', () => {
  test('Task dispatch with subagent_type writes a pretool-tagged spawn entry', () => {
    const result = syncTaskDispatcher(
      makeInput(
        { subagent_type: 'Explore', description: 'Map the hooks directory' },
        { tool_use_id: 'toolu_dispatch_1' },
      ),
    );

    expect(result.continue).toBe(true);
    const entries = spawnLogEntries();
    expect(entries.length).toBeGreaterThanOrEqual(1);
    const entry = entries[0];
    expect(entry.source).toBe('pretool');
    expect(entry.subagent_type).toBe('Explore');
    expect(entry.description).toBe('Map the hooks directory');
    expect(entry.tool_use_id).toBe('toolu_dispatch_1');
  });

  test('no spawn entry for Task inputs without subagent_type', () => {
    syncTaskDispatcher(makeInput({ description: 'not an Agent dispatch' }));
    expect(spawnLogEntries()).toHaveLength(0);
  });
});

describe('syncTaskDispatcher — task-agent-advisor registration', () => {
  test('general-purpose + debug-shaped input propagates the specialist nudge', () => {
    const result = syncTaskDispatcher(
      makeInput({
        subagent_type: 'general-purpose',
        description: 'Investigate the failure in CI and find the root cause',
        prompt: 'Trace the stack and explain why the deploy job crashed.',
      }),
    );

    expect(result.continue).toBe(true);
    const context = (result.hookSpecificOutput?.additionalContext as string) || '';
    expect(context).toContain('ork:debug-investigator');
    expect(context).toContain('general-purpose');
  });
});
